// ============================================================
//  UPGRADED CODE NODE — Angela Italy Instagram Workflow
//  Improvements: Data Validation + Richer Analytics +
//  Smarter Prompt + Performance Archive + Quality Gate
// ============================================================


// ================= SECTION 1: CONFIG =================

let sheetCfg = {};
try {
  const rows = $('Read Config1').all();
  for (const r of rows) {
    const key = r.json["Header Name"];
    const val = r.json["Example Value"];
    if (key) sheetCfg[key] = val;
  }
} catch (e) {}

const d = {
  brandName:        $('Read Config1').first().json.brandName,
  tone:     $('Read Config1').first().json.tone        ,
  audience: $('Read Config1').first().json.audience ,
  contentpillars:$('Read Config1').first().json.contentPillars,
  contentlanguage:$('Read Config1').first().json["Content Language"],
  blacklistWords: $('Read Config1').first().json.blacklistWords  ,
  captionstartegy:$('Read Config1').first().json["Caption Strategy"],
  minCaptionWords:  $('Read Config1').first().json.minCaptionWords,
  maxCaptionWords: $('Read Config1').first().json.maxCaptionWords ,
  maxHookChars:    $('Read Config1').first().json.maxHookChars ,
  minHashtags:      $('Read Config1').first().json.minHashtags,
  maxHashtags:     $('Read Config1').first().json.maxHashtags ,
  feedPostTime:     $('Read Config1').first().json.feedPostTime,
  morningStoryTime: $('Read Config1').first().json.morningStoryTime,
  eveningStoryTime: $('Read Config1').first().json.eveningStoryTime,
  bannedHashtags:  $('Read Config1').first().json.bannedHashtags ,
  colorPalette:     ''
};

const cfg = { ...d, ...sheetCfg };
cfg.minCaptionWords = Number(cfg.minCaptionWords);
cfg.maxCaptionWords = Number(cfg.maxCaptionWords);
cfg.maxHookChars    = Number(cfg.maxHookChars);
cfg.minHashtags     = Number(cfg.minHashtags);
cfg.maxHashtags     = Number(cfg.maxHashtags);

const blacklistArr = cfg.blacklistWords
  ? cfg.blacklistWords.split(',').map(w => w.trim().toLowerCase()).filter(Boolean)
  : [];


// ================= SECTION 2: HELPER FUNCTIONS =================

/**
 * Parses M/D/YYYY and YYYY-MM-DD date formats safely.
 */
const parseDate = (str) => {
  if (!str || typeof str !== 'string') return null;
  str = str.trim();
  if (str.includes('/')) {
    const [m, d, y] = str.split('/');
    if (!m || !d || !y) return null;
    const dt = new Date(`${y}-${m.padStart(2,'0')}-${d.padStart(2,'0')}`);
    return isNaN(dt.getTime()) ? null : dt;
  }
  if (/^\d{4}-\d{2}-\d{2}$/.test(str)) {
    const dt = new Date(str);
    return isNaN(dt.getTime()) ? null : dt;
  }
  return null;
};

/**
 * Normalizes EngagementRate — handles both 0.125 and 12.5 formats.
 */
const safeEngagement = (val) => {
  const n = parseFloat(val);
  if (isNaN(n) || n < 0) return 0;
  return n > 1 ? n / 100 : n;
};

/**
 * Returns a numeric value or 0 if the value is non-numeric / Excel artifact.
 */
const safeNum = (val) => {
  const n = Number(val);
  return isNaN(n) ? 0 : n;
};

/**
 * Validates a single analytics row.
 * Returns null if the row is too corrupt to use.
 */
const validateAnalyticsRow = (j) => {
  let issues = 0;

  const date     = parseDate(j.PostDate);
  const engRate  = safeEngagement(j.EngagementRate);
  const shares   = safeNum(j.Shares);
  const saves    = safeNum(j.Saves);
  const likes    = safeNum(j.Likes);
  const comments = safeNum(j.Comments);
  const reach    = safeNum(j.Reach);

  // Count critical empty fields
  if (!date)           issues++;
  if (!j.ContentType)  issues++;
  if (!j.Topic)        issues++;
  if (!j.HookStyle)    issues++;  // missing but recoverable

  // Reject rows with more than 2 critical issues
  if (issues > 2) return null;

  return {
    ...j,
    _parsedDate:    date,
    EngagementRate: engRate,
    Shares:         shares,
    Saves:          saves,
    Likes:          likes,
    Comments:       comments,
    Reach:          reach,
    HookStyle:      j.HookStyle || 'Unknown',
    ContentType:    j.ContentType || 'Unknown',
    // ── NEW enriched fields ──
    CaptionLength:  safeNum(j.CaptionLength),   // word count — add this column to sheet
    PostingHour:    safeNum(j.PostingHour),      // 0-23 — add this column to sheet
    HashtagCount:   safeNum(j.HashtagCount),     // number of hashtags — add to sheet
    HasCTA:         j.CallToAction === 'Yes',    // Yes/No column — add to sheet
    ProductFeatured:j.ProductFeatured || 'None'  // product name — add to sheet
  };
};


// ================= SECTION 3: SMART ARCHIVE =================

let pastTopics = '';
let archiveInsight = '';

try {
  const archiveRows = $('Read Archive').all().slice(-30);

  // Build topic list for avoidance
  pastTopics = archiveRows
    .map(i => i.json.Topic || '')
    .filter(Boolean)
    .join(', ');

  // Build performance memory — distinguish good vs bad past topics
  const goodTopics = archiveRows
    .filter(i => safeEngagement(i.json.EngagementRate) >= 0.05)  // 5%+ = good
    .map(i => i.json.Topic)
    .filter(Boolean);

  const badTopics = archiveRows
    .filter(i => safeEngagement(i.json.EngagementRate) > 0 && safeEngagement(i.json.EngagementRate) < 0.02)
    .map(i => i.json.Topic)
    .filter(Boolean);

  // Feed insight to AI
  if (goodTopics.length > 0 || badTopics.length > 0) {
    archiveInsight = `ARCHIVE PERFORMANCE MEMORY:
High-performing past topics (explore adjacent ideas): ${goodTopics.slice(0,5).join(', ') || 'None'}
Low-performing past topics (avoid these angles): ${badTopics.slice(0,5).join(', ') || 'None'}
INSTRUCTION: Generate topics adjacent to high-performers. Never revisit low-performers.`;
  }

} catch (e) {}


// ================= SECTION 4: ANALYTICS WITH DATA VALIDATION =================

let an = 'No historical data — use best practices for hook style, format, and topic selection.';

try {
  const r = $('Read Analytics').all();

  if (r.length > 0) {

    const cutoff = new Date();
    cutoff.setDate(cutoff.getDate() - 30);

    // Validate + sanitize every row
    const cleaned = r
      .map(i => validateAnalyticsRow(i.json))
      .filter(j => j !== null && j._parsedDate && j._parsedDate >= cutoff)
      .sort((a, b) => b.EngagementRate - a.EngagementRate);

    if (cleaned.length === 0) {
      an = 'No valid data in last 30 days — use best practices.';
    } else {

      const total = cleaned.length;

      // ── Avg engagement ──
      const avgEng = (cleaned.reduce((s, j) => s + j.EngagementRate, 0) / total * 100).toFixed(1);

      // ── Best content type ──
      const typeMap = {};
      cleaned.forEach(j => { typeMap[j.ContentType] = (typeMap[j.ContentType] || 0) + 1; });
      const bestType = Object.entries(typeMap).sort((a,b) => b[1]-a[1])[0]?.[0] || 'N/A';

      // ── Best hook style ──
      const hookMap = {};
      cleaned.forEach(j => { hookMap[j.HookStyle] = (hookMap[j.HookStyle] || 0) + 1; });
      const bestHook = Object.entries(hookMap).sort((a,b) => b[1]-a[1])[0]?.[0] || 'N/A';

      // ── Best posting hour ──
      const hourMap = {};
      cleaned.forEach(j => {
        if (j.PostingHour > 0) {
          hourMap[j.PostingHour] = (hourMap[j.PostingHour] || 0) + j.EngagementRate;
        }
      });
      const bestHour = Object.entries(hourMap).sort((a,b) => b[1]-a[1])[0]?.[0] || 'N/A';

      // ── Optimal caption length ──
      const captionLengths = cleaned.filter(j => j.CaptionLength > 0);
      const avgCaptionLen = captionLengths.length > 0
        ? Math.round(captionLengths.reduce((s,j) => s + j.CaptionLength, 0) / captionLengths.length)
        : 0;

      // ── CTA impact ──
      const withCTA    = cleaned.filter(j => j.HasCTA);
      const withoutCTA = cleaned.filter(j => !j.HasCTA);
      const ctaEngAvg  = withCTA.length > 0
        ? (withCTA.reduce((s,j) => s + j.EngagementRate, 0) / withCTA.length * 100).toFixed(1)
        : null;
      const noCTAEngAvg = withoutCTA.length > 0
        ? (withoutCTA.reduce((s,j) => s + j.EngagementRate, 0) / withoutCTA.length * 100).toFixed(1)
        : null;
      const ctaInsight = (ctaEngAvg && noCTAEngAvg)
        ? `CTAs: ${ctaEngAvg}% eng WITH vs ${noCTAEngAvg}% WITHOUT → ${parseFloat(ctaEngAvg) > parseFloat(noCTAEngAvg) ? 'ALWAYS include CTA' : 'CTA has no clear benefit'}`
        : '';

      // ── Optimal hashtag count ──
      const hashtagData = cleaned.filter(j => j.HashtagCount > 0);
      const avgHashtags = hashtagData.length > 0
        ? Math.round(hashtagData.reduce((s,j) => s + j.HashtagCount, 0) / hashtagData.length)
        : 0;

      // ── Best product ──
      const prodEngMap = {};
      const prodCountMap = {};
      cleaned.forEach(j => {
        if (j.ProductFeatured && j.ProductFeatured !== 'None') {
          prodEngMap[j.ProductFeatured]   = (prodEngMap[j.ProductFeatured]   || 0) + j.EngagementRate;
          prodCountMap[j.ProductFeatured] = (prodCountMap[j.ProductFeatured] || 0) + 1;
        }
      });
      const bestProduct = Object.entries(prodEngMap)
        .map(([k, v]) => ({ name: k, avg: v / prodCountMap[k] }))
        .sort((a, b) => b.avg - a.avg)[0]?.name || 'N/A';

      // ── Top 5 posts ──
      const top5 = cleaned.slice(0, 5).map(j =>
        `"${j.Topic}"(${j.ContentType}, Hook:${j.HookStyle}, E:${(j.EngagementRate*100).toFixed(1)}%, Saves:${j.Saves}, Shares:${j.Shares})`
      ).join('\n  → ');

      // ── Build structured analytics prompt ──
      an = `
ANALYTICS SUMMARY (last 30 days, ${total} validated posts):

PERFORMANCE STATS:
- Avg Engagement Rate: ${avgEng}%
- Best Content Format: ${bestType}
- Best Hook Style: ${bestHook}
- Best Posting Hour: ${bestHour}:00
- Optimal Caption Length: ${avgCaptionLen > 0 ? avgCaptionLen + ' words' : 'Not enough data'}
- Optimal Hashtag Count: ${avgHashtags > 0 ? avgHashtags : 'Not enough data'}
- Best Performing Product: ${bestProduct}
${ctaInsight ? '- ' + ctaInsight : ''}

TOP 5 POSTS (highest engagement):
  → ${top5}

AI REASONING INSTRUCTIONS (follow these steps before generating each post):
STEP 1 — Identify which 2 hook patterns from top posts you will replicate and state them.
STEP 2 — Identify which content format drove the most saves and use it for at least 2 posts.
STEP 3 — Identify which topic category drove the most shares and create at least 1 post in that category.
STEP 4 — Generate each post deliberately replicating the patterns found in steps 1-3.
STEP 5 — For each post in your JSON output, add an "analyticsInsight" field explaining which data point you applied.
      `.trim();
    }
  }
} catch(e) {
  an = 'Analytics unavailable — use best practices.';
}


// ================= SECTION 4.5: SMART LEARNING ENGINE =================
// Reads Template Performance sheet to dynamically allocate content formats
// and prefer better-performing templates

let smartAllocation = '';
let templatePreferences = '';
let dynamicFormatSplit = {
  singleImage: 3,
  carousel: 2,
  reel: 2
};

try {
  const perfData = $('Read Template Performance').all().map(i => i.json);

  if (perfData.length > 0) {
    // Calculate average performance score per content type
    const typeScores = {};
    const typeCounts = {};

    perfData.forEach(p => {
      const ct = (p.ContentType || '').toLowerCase();
      const score = Number(p.PerformanceScore) || 0;
      if (ct && score > 0) {
        typeScores[ct] = (typeScores[ct] || 0) + score;
        typeCounts[ct] = (typeCounts[ct] || 0) + 1;
      }
    });

    // Average scores per type
    const avgScores = {};
    for (const [type, total] of Object.entries(typeScores)) {
      avgScores[type] = total / typeCounts[type];
    }

    // Dynamic format allocation (weighted by performance)
    const siScore = avgScores['single_image'] || avgScores['image'] || 1;
    const carScore = avgScores['carousel'] || 1;
    const reelScore = avgScores['reel'] || 1;
    const totalScore = siScore + carScore + reelScore;

    if (totalScore > 3) { // Only use dynamic allocation if we have real data
      dynamicFormatSplit.carousel = Math.max(1, Math.min(4, Math.round(7 * carScore / totalScore)));
      dynamicFormatSplit.reel = Math.max(1, Math.min(4, Math.round(7 * reelScore / totalScore)));
      dynamicFormatSplit.singleImage = 7 - dynamicFormatSplit.carousel - dynamicFormatSplit.reel;
      // Ensure minimum 1 of each
      if (dynamicFormatSplit.singleImage < 1) {
        dynamicFormatSplit.singleImage = 1;
        dynamicFormatSplit.carousel = Math.min(dynamicFormatSplit.carousel, 3);
        dynamicFormatSplit.reel = 7 - dynamicFormatSplit.singleImage - dynamicFormatSplit.carousel;
      }

      smartAllocation = `\nSMART FORMAT ALLOCATION (data-driven from template performance):
- Single Images: ${dynamicFormatSplit.singleImage} posts (performance score: ${siScore.toFixed(1)})
- Carousels: ${dynamicFormatSplit.carousel} posts (performance score: ${carScore.toFixed(1)})
- Reels: ${dynamicFormatSplit.reel} posts (performance score: ${reelScore.toFixed(1)})
NOTE: This allocation is based on real engagement data. Prioritize the higher-scoring formats.\n`;
    }

    // Get top performing templates per content type + pillar
    const templateRankings = perfData
      .filter(p => Number(p.PerformanceScore) > 0)
      .sort((a, b) => Number(b.PerformanceScore) - Number(a.PerformanceScore))
      .slice(0, 10);

    if (templateRankings.length > 0) {
      const topTemplates = templateRankings
        .map(t => `- ${t.ContentType}/${t.Pillar}: Template "${t.TemplateName || t.TemplateID}" (score: ${Number(t.PerformanceScore).toFixed(1)}, used ${t.TimesUsed || 0} times)`)
        .join('\n');

      // Get worst performing templates to avoid
      const worstTemplates = perfData
        .filter(p => Number(p.PerformanceScore) > 0 && Number(p.TimesUsed) >= 2)
        .sort((a, b) => Number(a.PerformanceScore) - Number(b.PerformanceScore))
        .slice(0, 3)
        .map(t => `- AVOID "${t.TemplateName || t.TemplateID}" for ${t.ContentType} (score: ${Number(t.PerformanceScore).toFixed(1)})`)
        .join('\n');

      templatePreferences = `\nTEMPLATE PERFORMANCE PREFERENCES (use this to guide visual direction):
TOP PERFORMERS:
${topTemplates}
${worstTemplates ? '\nWEAK PERFORMERS (avoid these styles):\n' + worstTemplates : ''}
INSTRUCTION: Match your visual direction and content style to the top-performing templates.\n`;
    }
  }
} catch(e) {
  // Template performance data not available yet — use defaults
}


// ================= SECTION 5: PRODUCTS =================

let prodList = '';
let prodArr  = [];

try {
  const prods = $('Read Products').all().map(i => i.json)
    .filter(p => p.Status === 'Active' || p.Status === 'Seasonal');

  prods.sort((a, b) => {
    const pri = { High: 0, Medium: 1, Low: 2 };
    return (pri[a.Priority] || 1) - (pri[b.Priority] || 1);
  });

  prodArr = prods;

  if (prods.length > 0) {
    prodList = '\n\nPRODUCTS & SERVICES TO FEATURE:\n';
    prods.forEach((p, i) => {
      prodList += `${i+1}. ${p.Name} (${p.Category})\n`;
      prodList += `Description: ${p.Description}\n`;
      prodList += `Key Benefits: ${p.KeyBenefits || ''}\n`;
      prodList += `Content Angle: ${p.ContentAngle || 'Educational'}\n`;
      prodList += `Sample Hook: ${p.SampleHook || ''}\n`;
      prodList += `Promotion Style: ${p.PromotionStyle || 'Educational'}\n`;
      prodList += `Do NOT Say: ${p.DoNotSay || ''}\n`;
      prodList += `Target Audience: ${p.TargetAudience || cfg.audience}\n`;
      prodList += `Price: ${p.Price || ''}\n\n`;
    });
  }
} catch(e) {}


// ================= SECTION 6: PROMPTS =================

const sys = `You are a senior social media strategist for ${cfg.brandName}.
Tone: ${cfg.tone}.
Target Audience: ${cfg.audience}.
NEVER use these words or phrases: ${cfg.blacklistWords || 'none'}.

Your job is not just to generate content — it is to ANALYZE past performance data first, identify what patterns drove the highest engagement, saves and shares, then deliberately replicate those patterns in every piece of content you create.

RESPOND ONLY WITH A VALID JSON ARRAY. No explanations outside the JSON.`;

const fp = `
Generate 7 Instagram feed posts for next week as a JSON array.

FORMAT SPLIT:
- 3 SINGLE IMAGE posts (Monday, Thursday, Sunday)
- 2 CAROUSEL posts (Tuesday, Friday)
- 2 REELS posts (Wednesday, Saturday)

Content Pillar Balance: ${cfg.contentPillars}
Caption Length: ${cfg.minCaptionWords}–${cfg.maxCaptionWords} words
Hook Max Characters: ${cfg.maxHookChars}
Hashtags per post: ${cfg.minHashtags}–${cfg.maxHashtags}

AVOID THESE PAST TOPICS (already posted): ${pastTopics || 'None yet'}

${archiveInsight}

${an}

${prodList}

REQUIRED JSON FIELDS FOR EACH POST:
{
  "day": "Monday",
  "format": "SINGLE IMAGE | CAROUSEL | REEL",
  "pillar": "Education | Inspiration | Promotion",
  "topic": "...",
  "hook": "... (max ${cfg.maxHookChars} chars)",
  "caption": "... (${cfg.minCaptionWords}–${cfg.maxCaptionWords} words)",
  "hashtags": ["...", "..."],
  "callToAction": "...",
  "visualDirection": "...",
  "productFeatured": "Product name or None",
  "analyticsInsight": "Which past data pattern this post replicates and why"
}

Return ONLY the JSON array. No text before or after.
`.trim();


// ================= SECTION 7: QUALITY GATE =================

/**
 * Validates a single generated post against config rules.
 * Returns array of violation strings (empty = passed).
 */
const validatePost = (post) => {
  const violations = [];

  // Hook length
  if (post.hook && post.hook.length > cfg.maxHookChars) {
    violations.push(`Hook too long: ${post.hook.length} chars (max ${cfg.maxHookChars})`);
  }

  // Caption word count
  if (post.caption) {
    const wordCount = post.caption.trim().split(/\s+/).length;
    if (wordCount < cfg.minCaptionWords) violations.push(`Caption too short: ${wordCount} words (min ${cfg.minCaptionWords})`);
    if (wordCount > cfg.maxCaptionWords) violations.push(`Caption too long: ${wordCount} words (max ${cfg.maxCaptionWords})`);
  }

  // Hashtag count
  if (post.hashtags) {
    if (post.hashtags.length < cfg.minHashtags) violations.push(`Too few hashtags: ${post.hashtags.length} (min ${cfg.minHashtags})`);
    if (post.hashtags.length > cfg.maxHashtags) violations.push(`Too many hashtags: ${post.hashtags.length} (max ${cfg.maxHashtags})`);
  }

  // Blacklist words in caption + hook
  const fullText = `${post.hook || ''} ${post.caption || ''}`.toLowerCase();
  blacklistArr.forEach(word => {
    if (fullText.includes(word)) violations.push(`Blacklisted word found: "${word}"`);
  });

  // Missing critical fields
  ['day','format','topic','hook','caption','hashtags','callToAction'].forEach(field => {
    if (!post[field]) violations.push(`Missing required field: "${field}"`);
  });

  return violations;
};


// ================= SECTION 8: OUTPUT =================

const oai = JSON.stringify({
  model:      'gpt-4',
  messages:   [
    { role: 'system', content: sys },
    { role: 'user',   content: fp  }
  ],
  temperature: 0.7,
  max_tokens:  4000
});

const gem = JSON.stringify({
  contents: [{ parts: [{ text: sys + '\n\n' + fp }] }],
  generationConfig: { temperature: 0.7, maxOutputTokens: 4000 }
});

return [{
  json: {
    // AI request bodies
    openAiBody:       oai,
    geminiBody:       gem,

    // Config & context (for downstream nodes)
    config:           cfg,
    pastTopics:       pastTopics,
    archiveInsight:   archiveInsight,
    systemPrompt:     sys,
    userPrompt:       fp,
    products:         prodArr,
    dynamicFormatSplit: dynamicFormatSplit,
    smartAllocation:  smartAllocation,
    templatePreferences: templatePreferences,

    // Quality gate function (serialised for reference — call in a downstream Code Node)
    qualityGateInfo: `
After AI generates posts, add a Code Node that:
1. Parses the AI JSON response
2. Runs each post through the validatePost logic
3. Tags posts with violations as needsReview: true
4. Only auto-posts items where needsReview: false
    `.trim(),

    // Inline quality gate validator (use in downstream node)
    validatorLogic: validatePost.toString()
  }
}];

const cfg=$('Build Feed Prompt').first().json.config;
const days=[{d:'Monday',t:'single_image',p:'Education'},{d:'Tuesday',t:'carousel',p:'Inspiration'},{d:'Wednesday',t:'reel',p:'Promotion'},{d:'Thursday',t:'single_image',p:'Education'},{d:'Friday',t:'carousel',p:'Inspiration'},{d:'Saturday',t:'reel',p:'Education'},{d:'Sunday',t:'single_image',p:'Promotion'}];
const feedPosts=days.map(({d,t,p})=>({postType:t,scheduledDay:d,topic:p+' '+t+' - [MANUAL EDIT]',hook:'[EDIT] Scroll-stopping hook',caption:'Template for '+d+'. Brand: '+cfg.brandName+'. [MANUAL EDIT REQUIRED]',hashtags:['#content','#socialmedia','#instagram','#brand','#marketing','#creative','#engagement','#community','#growth','#strategy','#digital','#online','#trending','#viral','#inspo'],cta:'Follow for more! [EDIT]',visualBrief:'[EDIT] Visual description',slideText:t==='single_image'?'[EDIT]':'',script:t==='reel'?'[EDIT SCRIPT]':'',slideBreakdown:t==='carousel'?[{slideNum:1,title:'Cover',description:'Hook'},{slideNum:2,title:'Point 1',description:'[EDIT]'},{slideNum:3,title:'CTA',description:'Save'}]:undefined,sceneBreakdown:t==='reel'?[{scene:1,time:'0-3s',action:'Hook'},{scene:2,time:'3-15s',action:'Setup'},{scene:3,time:'15-25s',action:'Value'},{scene:4,time:'25-30s',action:'CTA'}]:undefined,pillar:p}));
