const inp=$input.first().json;let txt='',src='template';
if(inp.choices){txt=inp.choices[0].message.content;src='openai'}
else if(inp.candidates){txt=inp.candidates[0].content.parts[0].text;src='gemini'}
else if(inp.feedPosts)return[{json:{...inp,feedSource:inp.aiSource||'template'}}];
else txt=JSON.stringify(inp);
