let fp=JSON.parse(txt);if(!Array.isArray(fp))fp=fp.posts||[fp];
const cfg=$('Build Feed Prompt').first().json.config;const sys=$('Build Feed Prompt').first().json.systemPrompt;
const sp=`Generate 14 Instagram Stories as JSON array (2/day Mon-Sun):\nMORNING (${cfg.morningStoryTime}) 7 stories: Poll/Question/Tip/BTS/Quote\nEVENING (${cfg.eveningStoryTime}) 7 stories: connect to feed, drive engagement\nFeed posts: ${fp.map(p=>(p.scheduledDay||'')+': '+(p.topic||'')).join(', ')}\nEach: {day,timeSlot:"AM"/"PM",topic,storyType:"Poll/Question/Image/Video/Quote/BTS" mention type for each story,hook(max 15 chars attention-grabbing opener),mainText(max 50 chars),supportText(max 30),caption(max 100 chars engaging caption with emojis),cta(max 30 chars clear call-to-action),visualBrief(short description of visuals colors layout),background,interactiveElement:{type:"poll/question/none",question,options:["A","B"]},linkSticker,feedPostConnection,stickerSuggestions}\nRules: max 3 polls, min 2 polls, 1+ quiz, vary types, connect PM to feed. JSON only.`;
const soai=JSON.stringify({model:'gpt-4',messages:[{role:'system',content:sys},{role:'user',content:sp}],temperature:0.7,max_tokens:3500});
const sgem=JSON.stringify({contents:[{parts:[{text:sys+'\n\n'+sp}]}],generationConfig:{temperature:0.7,maxOutputTokens:3500}});
return[{json:{feedPosts:fp,feedSource:src,storyOpenAiBody:soai,storyGeminiBody:sgem}}];

