];

function df(day) {
  const d = new Date(mon);
  d.setDate(mon.getDate() + dn.indexOf(day));
  return d.toISOString().split('T')[0];
}

function chk(t, tags) {
  const f = [];
  const l = (t || '').toLowerCase();

  bl.forEach(w => {
    if (w && l.includes(w)) f.push('Blacklisted:' + w);
  });

  (Array.isArray(tags) ? tags : []).forEach(h => {
    if (bh.some(b => h.toLowerCase().replace('#', '') == b.replace('#', ''))) {
      f.push('Banned tag:' + h);
    }
  });

  return f;
}

