  // e.g. "Monday: [single_image] Men's Haircut & Style"
  const m = line.match(/^(\w+):\s*\[([^\]]+)\]\s*(.*)/);
  if (!m) return null;
  return {
    day:   m[1],
    type:  m[2].trim(),   // ✅ exact value from brackets: single_image | carousel | reel
    topic: m[3].trim()
  };
}).filter(Boolean);

// ── 5. PARSE STORY SCHEDULE ──
const storySection = message.match(/📲 Story Schedule:\n([\s\S]*?)(?=\n\nPillars:)/);
