  ? storySection[1].trim().split('\n').map(l => l.trim()).filter(Boolean)
  : [];

const storyRows = storyLines.map(line => {
  // e.g. "Monday (9:00:00 AM): [Poll] What is your preferred beauty treatment?"
  const m = line.match(/^(\w+)\s*\(([^)]+)\):\s*\[([^\]]+)\]\s*(.*)/);
  if (!m) return null;
  const timeRaw    = m[2].trim();
  const timeParts  = timeRaw.match(/(\d+:\d+)(?::\d+)?\s*(AM|PM)/i);
  const displayTime = timeParts
    ? `${timeParts[1]} ${timeParts[2].toUpperCase()}`
    : timeRaw;
  return {
    dayAbbr:     m[1].substring(0, 3).toUpperCase(),
    displayTime,
    type:        m[3].trim(),
    topic:       m[4].trim()
  };
}).filter(Boolean);

