function typePill(type) {
  const t = type.toLowerCase().replace(/[\s-]+/g, '_');

  let label, bg, color, border;

  if (t.includes('carousel')) {
    label  = 'CAROUSEL';
    bg     = '#EBF5FB';
    color  = '#1A6FA0';
    border = '#AED6F1';
  } else if (t.includes('reel')) {
    label  = 'REEL';
    bg     = '#F4ECF7';
    color  = '#7D3C98';
    border = '#D7BDE2';
  } else if (t.includes('single') || t.includes('image')) {
    label  = 'IMAGE';
    bg     = '#FEF9EC';
    color  = '#9A6C00';
    border = '#F0D080';
  } else {
    // fallback — show raw label
    label  = type.toUpperCase().replace(/_/g,' ');
    bg     = '#F5F5F5';
    color  = '#555555';
    border = '#DDDDDD';
  }

  return `<span style="display:inline-block;padding:4px 12px;border-radius:100px;` +
    `font-family:'Courier New',monospace;font-size:9px;letter-spacing:1px;font-weight:700;` +
    `background:${bg};color:${color};border:1px solid ${border};">${label}</span>`;
}

