// Format Telegram status notification after content plan is created
const cfg = $('Read Config1').first().json;
const summary = $('Build Summary').first().json;

const telegramToken = cfg.telegramBotToken || '';
const chatId = cfg.telegramChatId || '';

if (!telegramToken || !chatId || telegramToken === 'YOUR_BOT_TOKEN') {
  return [{ json: { skip: true, reason: 'Telegram not configured' } }];
}

const now = new Date();
const weekStart = new Date(now);
weekStart.setDate(now.getDate() + 1); // Next Monday
while (weekStart.getDay() !== 1) weekStart.setDate(weekStart.getDate() + 1);
const weekLabel = weekStart.toISOString().split('T')[0];

const totalContent = summary.totalContent || 21;
const totalFeed = summary.totalFeed || 7;
const totalStories = summary.totalStories || 14;
const flaggedCount = summary.flaggedCount || 0;
const feedSource = (summary.feedSource || 'AI').toUpperCase();

let msg = `📋 *CONTENT PLAN CREATED*\n`;
msg += `Week of ${weekLabel}\n\n`;
msg += `📊 *Summary:*\n`;
msg += `• Total: ${totalContent} pieces\n`;
msg += `• Feed Posts: ${totalFeed}\n`;
msg += `• Stories: ${totalStories}\n`;
msg += `• Flagged: ${flaggedCount}\n`;
msg += `• AI Source: ${feedSource}\n\n`;
msg += `🎨 *Next Step:* Visuals are being generated...\n`;
msg += `You'll receive a preview with approval buttons once ready.`;

return [{
  json: {
    telegramToken,
    chatId,
    message: msg,
    skip: false
  }
}];
